const files = $input.first().json;
if (!Array.isArray(files)) return [{ json: { error: 'Could not list source files' } }];

const SAMPLE_SIZE = 10;
const jsonFiles = files.filter(f => f.name.endsWith('.json') && !f.name.startsWith('_'));

// Pick a random sample to avoid hitting all 51 DOR sites monthly
const shuffled = jsonFiles.sort(() => Math.random() - 0.5);
const sample = shuffled.slice(0, SAMPLE_SIZE);

const statesToValidate = [];
for (const f of sample) {
  try {
    const rawResp = await this.helpers.httpRequest({
      method: 'GET',
      url: f.download_url,
      headers: { 'User-Agent': 'n8n-paperwork' }
    });
    const source = typeof rawResp === 'string' ? JSON.parse(rawResp) : rawResp;
    statesToValidate.push({
      state: source.state,
      state_name: source.state_name,
      dor_url: source.dor?.url || null,
      tax_foundation_url: source.tax_foundation?.url || null
    });
  } catch (e) {
    // skip
  }
}

return [{ json: { states: statesToValidate } }];

const { states } = $input.first().json;
if (!states || states.length === 0) return [{ json: { results: [], error: 'No states to validate' } }];

const ghToken = $env.GITHUB_TOKEN || '';
const ghHeaders = { Accept: 'application/vnd.github.v3.raw', 'User-Agent': 'n8n-paperwork' };
if (ghToken) ghHeaders.Authorization = `Bearer ${ghToken}`;

const results = [];

for (const st of states) {
  const result = { state: st.state, state_name: st.state_name, issues: [], status: 'ok' };

  // Fetch our stored tax data for the latest year
  let storedData = null;
  for (const year of [2026, 2025, 2024]) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://api.github.com/repos/paperwork-labs/paperwork/contents/packages/data/src/tax/${year}/${st.state}.json`,
        headers: ghHeaders
      });
      storedData = typeof resp === 'string' ? JSON.parse(resp) : resp;
      break;
    } catch (e) { /* try next year */ }
  }

  if (!storedData) {
    result.status = 'error';
    result.issues.push('Could not fetch stored tax data from GitHub');
    results.push(result);
    continue;
  }

  // Fetch DOR page content if available
  let dorContent = '';
  if (st.dor_url) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: st.dor_url,
        headers: { 'User-Agent': 'Mozilla/5.0 (compatible; PaperworkLabs/1.0; data-validator)', Accept: 'text/html' },
        timeout: 15000
      });
      dorContent = String(typeof resp === 'string' ? resp : (resp.body || ''))
        .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
        .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
        .replace(/<[^>]+>/g, ' ')
        .replace(/\s+/g, ' ')
        .trim()
        .slice(0, 20000);
    } catch (e) {
      result.issues.push(`DOR page fetch failed: ${String(e).slice(0, 100)}`);
    }
  }

  // Basic cross-validation: check if our stored top rate appears on the DOR page
  if (dorContent && storedData.income_tax) {
    const it = storedData.income_tax;
    let topRatePct = '0';
    if (it.type === 'flat') topRatePct = (it.flat_rate_bps / 100).toFixed(2);
    if (it.type === 'progressive') {
      let max = 0;
      for (const brackets of Object.values(it.brackets || {})) {
        for (const b of brackets) {
          if (b.rate_bps > max) max = b.rate_bps;
        }
      }
      topRatePct = (max / 100).toFixed(2);
    }

    if (it.type !== 'none') {
      const rateStr = topRatePct.replace(/0$/, '');
      const altRateStr = (parseFloat(topRatePct)).toString();
      const found = dorContent.includes(rateStr) || dorContent.includes(altRateStr) || dorContent.includes(topRatePct + '%') || dorContent.includes(altRateStr + '%');
      if (!found && dorContent.length > 500) {
        result.issues.push(`Top rate ${topRatePct}% not found on DOR page (may be layout change)`);
      }
    }
  }

  results.push(result);
}

return [{ json: { results, timestamp: new Date().toISOString() } }];

const { results, timestamp } = $input.first().json;
const botToken = $env.SLACK_BOT_TOKEN || '';
if (!botToken) return [];

const withIssues = results.filter(r => r.issues && r.issues.length > 0);
const clean = results.filter(r => r.issues.length === 0 && r.status === 'ok');

const parts = [`*Monthly Data Validator — ${results.length} states sampled*\n`];

if (withIssues.length > 0) {
  parts.push(':warning: *Issues Found*');
  for (const r of withIssues) {
    parts.push(`\u2022 *${r.state}* (${r.state_name}): ${r.issues.join('; ')}`);
  }
  parts.push('');
}

parts.push(`:white_check_mark: ${clean.length}/${results.length} states validated clean`);

if (withIssues.length > 0) {
  parts.push('\n:point_right: Investigate flagged states. Run `pnpm review` for full check.');
}

const message = parts.join('\n');
return [{ json: { message, channel: 'C0ALVM4PAE7' } }];
